fn install_shen_x2e_initialise_x2d_lambda_x2d_forms(interp: &mut Interp) {
    interp.register_native(
        "shen.initialise-lambda-forms",
        0,
        aot_shen_x2e_initialise_x2d_lambda_x2d_forms,
    );
    interp.register_aot_direct(
        "shen.initialise-lambda-forms",
        aot_shen_x2e_initialise_x2d_lambda_x2d_forms,
    );
}

/// AOT-compiled from KL `(defun shen.initialise ...)`
pub fn aot_shen_x2e_initialise(interp: &mut Interp, args: &[Value]) -> ShenResult<Value> {
    if args.len() != 0 {
        return Err(ShenError::new(format!(
            "shen.initialise: expected 0 args, got {}",
            args.len()
        )));
    }
    #[allow(clippy::never_loop)]
    loop {
        {
            let _ = { rt::apply_direct(interp, "shen.initialise-environment", &[])? };
            {
                let _ = { rt::apply_direct(interp, "shen.initialise-lambda-forms", &[])? };
                break Ok({ rt::apply_direct(interp, "shen.initialise-signedfuncs", &[])? });
            }
        }
    }
}

fn install_shen_x2e_initialise(interp: &mut Interp) {
    interp.register_native("shen.initialise", 0, aot_shen_x2e_initialise);
    interp.register_aot_direct("shen.initialise", aot_shen_x2e_initialise);
}

/// Register every AOT-compiled function on `interp`. Call after kernel
/// boot so these names override the tree-walked defuns.
pub fn install(interp: &mut Interp) {
    install_shen_x2e_initialise_x2d_environment(interp);
    install_shen_x2e_initialise_x2d_signedfuncs(interp);
    install_shen_x2e_initialise_x2d_lambda_x2d_forms(interp);
    install_shen_x2e_initialise(interp);
}
